def dfs(u, p):
    big = set()
    for v in g[u]:
        if v == p:
            continue
        child = dfs(v, u)
        if len(child) > len(big):
            big, child = child, big
        big |= child
    big.add(colors[u])
    res[u] = len(big)
    return big

